-- =====================================================================
-- SmartTds  MASTER database schema  (PostgreSQL)
-- Converted from MasterDbTdsScript.utf8.sql (SQL Server). 28 tables.
-- Apply once:  CREATE DATABASE smarttds_master; \c smarttds_master; \i this_file
--
-- CONVERSION CONVENTIONS (see PHASE1_SCHEMA_NOTES.md):
--   * all identifiers lowercased (PG folds unquoted -> lowercase; Npgsql
--     reader lookups are case-insensitive, so C# mapping keeps working).
--   * int IDENTITY(1,1)      -> integer GENERATED BY DEFAULT AS IDENTITY
--     (BY DEFAULT so seed rows can carry explicit ids)
--   * nvarchar(n)            -> varchar(n)
--   * nvarchar(max)          -> text
--   * bit                    -> boolean   (default 0->false, 1->true)
--   * datetime / smalldatetime -> timestamp
--   * decimal(p,s)/numeric(p,s) -> numeric(p,s)   (preserved exactly)
--   * float / real           -> double precision
--   * image / varbinary      -> bytea
--   * date                   -> date   (kept as-is; SQL Server date = PG date)
--   * getdate()              -> now()
--   * RESERVED WORD columns that require quoting (verified against PG16):
--       "limit"  -> column in tdsentriessection and tdsrate (LIMIT is reserved).
--       These MUST be quoted in the BAL queries too. All other identifiers
--       here (name, value, mode, date, number, period, state, status, section)
--       are NON-reserved in PG and need no quoting.
--   * FOREIGN KEYS are added at the END of this file (after all tables) so
--     creation order is independent of declaration order.
-- =====================================================================

-- ---------- ApplicationParams ----------
CREATE TABLE applicationparams (
    id      integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    name    varchar(100),
    value   text
);

