-- ---------- AssesseeRep ----------
CREATE TABLE assesseerep (
    id              integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    subcode         integer NOT NULL,
    repname         varchar(125) NOT NULL,
    repfathername   varchar(125),
    reppan          varchar(10),
    repcapacity     varchar(5),
    repaddress      varchar(250),
    repaadhaar      varchar(12),
    place           varchar(50),
    isdeleted       boolean NOT NULL
);

-- ---------- AssesseeResStatus ----------
CREATE TABLE assesseeresstatus (
    id              integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    subcode         integer NOT NULL,
    ayid            integer NOT NULL,
    resstatus       varchar(10) NOT NULL,
    modifiedon      timestamp NOT NULL,
    resstatusval    text
);

-- ---------- AyMaster ----------
CREATE TABLE aymaster (
    id          integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    ayid        integer NOT NULL,
    name        varchar(15) NOT NULL,
    startdt     varchar(10) NOT NULL,
    enddt       varchar(10) NOT NULL,
    nonbusinc   varchar(10),
    businc      varchar(10),
    auditcase   varchar(10),
    compcase    varchar(10),
    case94e     varchar(10),
    advinst1    varchar(10),
    advinst2    varchar(10),
    advinst3    varchar(10),
    advinst4    varchar(10),
    updnonbusinc varchar(10),
    updbusinc   varchar(10),
    updauditcase varchar(10),
    updcompcase varchar(10),
    updcase94e  varchar(10)
);

-- ---------- BankDetails ----------
CREATE TABLE bankdetails (
    id              integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    subcode         integer NOT NULL,
    bankname        varchar(125) NOT NULL,
    branchname      varchar(50) NOT NULL,
    bankadd         varchar(50),
    bankacno        varchar(20) NOT NULL,
    ifsccode        varchar(11) NOT NULL,
    bsrno           varchar(79),
    micrno          varchar(9),
    typecode        varchar(50),
    ecs             varchar(10) NOT NULL,
    createdby       integer NOT NULL,
    createdon       timestamp NOT NULL,
    modifiedby      integer NOT NULL,
    modifiedon      timestamp NOT NULL,
    isdeleted       boolean NOT NULL,
    appliestoyear   varchar(100) NOT NULL DEFAULT '0'
);

-- ---------- BillDetails ----------
CREATE TABLE billdetails (
    id              integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    billid          integer NOT NULL,
    description     varchar(50) NOT NULL,
    prodcode        numeric(8,0),
    unit            varchar(10),
    qty             numeric(12,2),
    value           numeric(15,2) NOT NULL,
    discount        numeric(18,2),
    taxablevalue    numeric(15,2) NOT NULL,
    ratemain        numeric(5,2) NOT NULL,
    amtigst         numeric(15,2),
    amtcgst         numeric(15,2),
    amtsgst         numeric(15,2),
    amtcess         numeric(15,2),
    totamount       numeric(15,2) NOT NULL
);

-- ---------- BillHead ----------
CREATE TABLE billhead (
    id              integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    subcode         integer NOT NULL,
    ayid            integer NOT NULL,
    periodid        integer,
    conscode        integer NOT NULL,
    billno          integer NOT NULL,
    billdt          date NOT NULL,
    pos             integer NOT NULL,
    totamt          numeric(15,3) NOT NULL,
    amtreceived     numeric(15,3) NOT NULL,
    amtdisc         numeric(15,3) NOT NULL,
    createdby       integer,
    createdon       timestamp,
    modifiedby      integer,
    modifiedon      timestamp,
    isdeleted       boolean NOT NULL DEFAULT false
);

-- ---------- Billmast ----------
CREATE TABLE billmast (
    billid      integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    date        varchar(50),
    subcode     integer DEFAULT 0,
    billno      integer DEFAULT 0,
    p1          varchar(500),
    p1amt       numeric(18,2) DEFAULT 0,
    p2          varchar(500),
    p2amt       numeric(18,2) DEFAULT 0,
    p3          varchar(500),
    p3amt       numeric(18,2) DEFAULT 0,
    p4          varchar(500),
    p4amt       numeric(18,2) DEFAULT 0,
    p5          varchar(500),
    p5amt       numeric(18,2) DEFAULT 0,
    p6          varchar(500),
    p6amt       numeric(18,2) DEFAULT 0,
    p7          varchar(500),
    p7amt       numeric(18,2) DEFAULT 0,
    p8          varchar(500),
    p8amt       numeric(18,2) DEFAULT 0,
    p9          varchar(500),
    p9amt       numeric(18,2) DEFAULT 0,
    p10         varchar(500),
    p10amt      numeric(18,2) DEFAULT 0,
    stax        numeric(18,2) DEFAULT 0,
    tamt        numeric(18,2) DEFAULT 0,
    sperc       numeric(18,2) DEFAULT 0,
    ramt        numeric(18,2) DEFAULT 0,
    ayid        integer DEFAULT 0,
    conscode    integer DEFAULT 0,
    damt        numeric(18,2) DEFAULT 0,
