    grpcode     integer DEFAULT 0,
    modifiedon  timestamp DEFAULT now(),
    isdeleted   boolean DEFAULT false
);

-- ---------- BillReceipt ----------
CREATE TABLE billreceipt (
    receiptno   integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    date        varchar(50),
    subcode     integer DEFAULT 0,
    billno      integer DEFAULT 0,
    amount      numeric(18,2) DEFAULT 0,
    mode        varchar(50),
    number      varchar(100),
    billdate    varchar(50),
    ayid        integer DEFAULT 0,
    conscode    integer DEFAULT 0,
    discount    numeric(18,2) DEFAULT 0,
    billid      integer DEFAULT 0,
    userid      integer DEFAULT 0,
    lastupdate  varchar(50),
    modifiedon  timestamp DEFAULT now(),
    isdeleted   boolean DEFAULT false
);

-- ---------- BillReceipts ----------
CREATE TABLE billreceipts (
    id              integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    ayid            integer NOT NULL,
    billid          integer NOT NULL,
    receiptno       integer NOT NULL,
    receiptdt       date NOT NULL,
    amtreceived     numeric(15,3) NOT NULL,
    amtdisc         numeric(15,3) NOT NULL,
    mode            varchar(50) NOT NULL,
    instrumentno    varchar(50),
    instrumentdt    date,
    createdby       integer,
    createdon       timestamp,
    modifiedby      integer,
    modifiedon      timestamp,
    isdeleted       boolean NOT NULL DEFAULT false
);

-- ---------- Check_period ----------
CREATE TABLE check_period (
    id          integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    quarter     integer DEFAULT 0,
    month       integer DEFAULT 0,
    ayid        integer DEFAULT 0
);

-- ---------- Consultant ----------
CREATE TABLE consultant (
    conscode                        integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    prodkey                         varchar(10) NOT NULL,
    name                            varchar(50) NOT NULL,
    residenceno                     varchar(50) NOT NULL,
    residencename                   varchar(50) NOT NULL,
    roadorstreet                    varchar(50) NOT NULL,
    localityorarea                  varchar(50),
    city                            varchar(50) NOT NULL,
    statecode                       varchar(50),
    state                           varchar(50) NOT NULL,
    phoneoffice                     varchar(11) NOT NULL,
    phoneresi                       varchar(50) NOT NULL,
    mobile                          varchar(11) NOT NULL,
    mobile2                         varchar(50) NOT NULL,
    email                           varchar(125) NOT NULL,
    partnername                     varchar(50) NOT NULL,
    membership                      varchar(20),
    partnerdesignation              varchar(50) NOT NULL,
    slogan                          varchar(32) NOT NULL,
    bankname                        varchar(100),
    accno                           varchar(25),
    ifsccode                        varchar(11),
    panfirm                         varchar(10),
    frnno                           varchar(7),
    panpartner                      varchar(10),
    pin                             numeric(7,0) NOT NULL,
    gstno                           varchar(15),
    userid                          varchar(10),
    pwd                             varchar(25),
    emailprovider                   varchar(20),
    emailid                         varchar(50),
    emailpwd                        varchar(50),
    flagdefault                     boolean NOT NULL,
    logo                            text,
    emailsignature                  text,
    flagpendingbillsnotifications   boolean NOT NULL DEFAULT true,
    createdby                       integer NOT NULL,
    createdon                       timestamp NOT NULL,
    modifiedby                      integer NOT NULL,
    modifiedon                      timestamp NOT NULL,
    isdeleted                       boolean NOT NULL
);

-- ---------- Country ----------
CREATE TABLE country (
    id      integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    code    integer NOT NULL,
    name    varchar(50) NOT NULL
);

-- ---------- District ----------
CREATE TABLE district (
    id          integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    code        integer NOT NULL,
    statecode   integer NOT NULL,
    name        varchar(255) NOT NULL
);

-- ---------- FeePaidMarking ----------
CREATE TABLE feepaidmarking (
    id          integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    subcode     integer NOT NULL,
    fyid        integer NOT NULL,
    periodid    integer,
    feepaid     boolean NOT NULL DEFAULT false,
    notes       text,
    createdon   timestamp NOT NULL,
    modifiedon  timestamp
);

-- ---------- Groups ----------
CREATE TABLE groups (
    grpcode     integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    prodkey     varchar(10) NOT NULL,
    groupname   varchar(100),
    createdby   integer NOT NULL,
    createdon   timestamp NOT NULL,
    modifiedby  integer NOT NULL,
    modifiedon  timestamp NOT NULL,
    isdeleted   boolean NOT NULL DEFAULT false,
    email       varchar(75),
    mobile      varchar(10)
);

-- ---------- Pincode ----------
-- (no IDENTITY in source; no PK defined; use serial for consistency)
CREATE TABLE pincode (
    id              integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    pincode         double precision,
    districtcode    double precision,
    statecode       double precision,
    subdistrictcode double precision,
    localitycode    double precision,
    postofficecode  double precision
);

-- ---------- PostOffice ----------
CREATE TABLE postoffice (
    id      integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    code    integer NOT NULL,
    name    varchar(255) NOT NULL
);

-- ---------- ReturnDates ----------
-- No explicit IDENTITY PK in source; add serial surrogate for PG
CREATE TABLE returndates (
    id                  integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    subcode             integer NOT NULL,
    ayid                integer NOT NULL,
    quarter             varchar(5) NOT NULL,
    signingdate         varchar(10) NOT NULL,
    place               varchar(75),
    formname            varchar(10) NOT NULL,
    tokennumber         varchar(15),
    addresschangeorg    boolean NOT NULL DEFAULT false,
    addresschangeauth   boolean NOT NULL DEFAULT false,
    aoapprovalnu        varchar(20),
    isregularstatement  boolean NOT NULL DEFAULT true,
    isnilreturn         boolean NOT NULL DEFAULT false,
    nilsectionscount    integer NOT NULL DEFAULT 0
);

CREATE UNIQUE INDEX uq_returndates_perquarterform
    ON returndates (subcode, ayid, quarter, formname);

-- ---------- State ----------
CREATE TABLE state (
    id      integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    code    integer NOT NULL,
    name    varchar(50) NOT NULL
);

-- ---------- SubDistrict ----------
CREATE TABLE subdistrict (
    id      integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    code    integer NOT NULL,
    name    varchar(50) NOT NULL
);

