    radd1       varchar(200),
    radd2       varchar(200),
    radd3       varchar(200),
    radd4       varchar(200),
    rcity       varchar(100),
    rstatecode  integer DEFAULT 0,
    rpin        varchar(20),
    rstd        varchar(20),
    rphone      varchar(50),
    remail      varchar(200),
