-- ---------- Tdsded80 ----------
CREATE TABLE tdsded80 (
    ded80id     integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    dedsec      varchar(20),
    ded80name   varchar(200),
    ded80table  varchar(50),
