-- ---------- TdsEntriesSection ----------
-- No PK in source
CREATE TABLE tdsentriessection (
    section     varchar(10),
    paycode     integer,
    name        varchar(200),
    "limit"     integer,
    formname    varchar(6),
    newsection  varchar(50)
);

-- ---------- TdsNature ----------
CREATE TABLE tdsnature (
    particular  varchar(255),
    code        integer NOT NULL,
    CONSTRAINT pk_nature3 PRIMARY KEY (code)
);

-- ---------- TdsRate ----------
-- No PK in source
CREATE TABLE tdsrate (
    ayid    integer,
    tsid    integer,
    paycode integer,
    rate    numeric(5,2),
    surch   numeric(5,2),
    "limit" integer
);

-- ---------- Users ----------
CREATE TABLE users (
    userid                  integer GENERATED BY DEFAULT AS IDENTITY,
    prodkey                 varchar(10) NOT NULL,
    username                varchar(50) NOT NULL,
    name                    varchar(50) NOT NULL,
    pwd                     varchar(500) NOT NULL,
    emailid                 varchar(150) NOT NULL,
    mobile                  varchar(10) NOT NULL,
    usertype                varchar(40) NOT NULL,
    assesseeaddflag         boolean NOT NULL,
    assesseeeditflag        boolean NOT NULL,
    assesseedeleteflag      boolean NOT NULL,
    viewpwdflag             boolean NOT NULL,
    backupflag              boolean NOT NULL,
    restoreflag             boolean NOT NULL,
    efilingflag             boolean NOT NULL,
    rptviewflag             boolean NOT NULL,
    editfiledreturnflag     boolean NOT NULL,
    selectedper             integer,
    createdby               integer NOT NULL,
    createdon               timestamp NOT NULL,
    modifiedby              integer NOT NULL,
    modifiedon              timestamp NOT NULL,
    isdeleted               boolean NOT NULL,
    CONSTRAINT pk_users PRIMARY KEY (prodkey, username)
);

-- ---------- FOREIGN KEYS (added last, order-independent) ----------
ALTER TABLE billhead     ADD CONSTRAINT fk_billhead_assessee
    FOREIGN KEY (subcode) REFERENCES assessee(subcode);
ALTER TABLE billdetails  ADD CONSTRAINT fk_billdetails_billhead
    FOREIGN KEY (billid) REFERENCES billhead(id) ON DELETE CASCADE;
ALTER TABLE billreceipts ADD CONSTRAINT fk_billreceipts_billhead
    FOREIGN KEY (billid) REFERENCES billhead(id);
